'use client';

interface TabsProps {
  currentChannel: string;
  onChannelChange: (channel: string) => void;
}

const channels = [
  { id: 'home', name: '🔥 热门' },
  { id: 'business', name: '💼 商机' },
  { id: 'resource', name: '🤝 资源' },
  { id: 'tech', name: '💻 技术' },
  { id: 'finance', name: '💰 融资' },
  { id: 'events', name: '🎉 活动' },
];

export default function Tabs({ currentChannel, onChannelChange }: TabsProps) {
  return (
    <div className="bg-white rounded-xl p-2 mb-4 border border-gray-200 shadow-sm overflow-x-auto">
      <div className="flex gap-1 min-w-max">
        {channels.map((channel) => (
          <button
            key={channel.id}
            onClick={() => onChannelChange(channel.id)}
            className={`px-3 sm:px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all ${
              currentChannel === channel.id
                ? 'bg-indigo-500 text-white'
                : 'hover:bg-gray-100 text-gray-700'
            }`}
          >
            {channel.name}
          </button>
        ))}
      </div>
    </div>
  );
}
