'use client';

import { Post, Company } from '../data';

interface PostModalProps {
  post: Post | null;
  isOpen: boolean;
  onClose: () => void;
  onAuthorClick: () => void;
  onCommentClick: () => void;
}

export function PostModal({ post, isOpen, onClose, onAuthorClick, onCommentClick }: PostModalProps) {
  if (!isOpen || !post) return null;

  return (
    <div 
      className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4 modal-overlay"
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div className="bg-white rounded-2xl max-w-2xl w-full max-h-[85vh] overflow-y-auto modal-content">
        <div className="sticky top-0 bg-white border-b border-gray-200 px-6 py-4 flex justify-between items-center">
          <h3 className="text-xl font-bold text-indigo-600">📝 帖子详情</h3>
          <button 
            onClick={onClose}
            className="w-10 h-10 rounded-full bg-gray-100 hover:bg-red-500 hover:text-white flex items-center justify-center text-xl transition-all"
          >
            ×
          </button>
        </div>
        
        <div className="p-6">
          <div className="flex items-center gap-4 mb-4">
            <div 
              className="w-14 h-14 rounded-full flex items-center justify-center text-white font-bold text-xl cursor-pointer hover:opacity-80"
              style={{ backgroundColor: post.author.avatarColor }}
              onClick={onAuthorClick}
            >
              {post.author.logo}
            </div>
            <div>
              <div 
                className="font-bold text-lg cursor-pointer hover:text-indigo-600"
                onClick={onAuthorClick}
              >
                {post.author.name}
              </div>
              <div className="text-gray-500 text-sm">
                {post.author.industry} · {post.timestamp}
              </div>
            </div>
          </div>
          
          <h2 className="text-2xl font-bold mb-4 text-gray-900">{post.title}</h2>
          
          <div className="text-gray-700 leading-relaxed whitespace-pre-line mb-6">
            {post.content}
          </div>
          
          <div className="flex gap-3">
            <button 
              onClick={onCommentClick}
              className="px-5 py-2.5 bg-cyan-500 text-white rounded-full font-medium hover:bg-cyan-600 transition"
            >
              💬 查看评论
            </button>
            <button 
              onClick={onAuthorClick}
              className="px-5 py-2.5 bg-green-500 text-white rounded-full font-medium hover:bg-green-600 transition"
            >
              🏢 查看企业
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

