interface CommentModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export function CommentModal({ isOpen, onClose }: CommentModalProps) {
  if (!isOpen) return null;

  const comments = [
    { author: '科栖实业', avatarColor: '#667eea', text: '您好！贵公司的业务很有吸引力，能否提供更多资料？', time: '2小时前' },
    { author: '冠一医疗', avatarColor: '#11998e', text: '这个方向我们一直在探索，希望能在技术上互相支持！', time: '3小时前' },
    { author: '北京银行', avatarColor: '#f093fb', text: '我司有类似需求，可以安排一次面对面洽谈。', time: '5小时前' },
  ];

  return (
    <div 
      className="fixed inset-0 bg-black/70 z-50 flex items-center justify-center p-4 modal-overlay"
      onClick={(e) => e.target === e.currentTarget && onClose()}
    >
      <div className="bg-white rounded-2xl max-w-xl w-full max-h-[85vh] overflow-y-auto modal-content">
        <div className="sticky top-0 bg-white border-b border-gray-200 px-6 py-4 flex justify-between items-center">
          <h3 className="text-xl font-bold text-indigo-600">💬 全部评论</h3>
          <button 
            onClick={onClose}
            className="w-10 h-10 rounded-full bg-gray-100 hover:bg-red-500 hover:text-white flex items-center justify-center text-xl transition-all"
          >
            ×
          </button>
        </div>
        
        <div className="p-6">
          <div className="space-y-4 mb-6">
            {comments.map((comment, index) => (
              <div key={index} className="p-4 bg-gray-50 rounded-xl">
                <div className="flex items-center gap-3 mb-2">
                  <div 
                    className="w-9 h-9 rounded-full flex items-center justify-center text-white font-bold text-sm"
                    style={{ backgroundColor: comment.avatarColor }}
                  >
                    {comment.author[0]}
                  </div>
                  <span className="font-bold text-gray-900">{comment.author}</span>
                </div>
                <p className="text-gray-600 text-sm mb-2">{comment.text}</p>
                <div className="text-xs text-gray-400">{comment.time}</div>
              </div>
            ))}
          </div>
          
          <div className="border-t border-gray-200 pt-4">
            <h4 className="font-bold text-gray-900 mb-3">回复此帖</h4>
            <textarea 
              className="w-full p-3 border-2 border-gray-200 rounded-xl text-sm min-h-[100px] focus:border-indigo-500 focus:outline-none resize-none mb-3"
              placeholder="写下你的回复..."
            />
            <button className="px-6 py-2.5 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-full font-medium hover:opacity-90 transition">
              发布回复
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
