export function generatePosts(channel: string = 'home', count: number = 20): Post[] {
  const posts: Post[] = [];
  
  for (let i = 0; i < count; i++) {
    const company = companies[i % companies.length];
    
    let keyword = "";
    let topic = "";
    
    switch(channel) {
      case 'business':
        keyword = ["招商引资", "商务合作", "项目发包"][i % 3];
        topic = ["土地厂房", "OEM 代工", "联合投标"][i % 3];
        break;
      case 'resource':
        keyword = ["人才招聘", "场地租赁", "设备共享"][i % 3];
        topic = ["高级人才", "写字楼", "实验仪器"][i % 3];
        break;
      case 'tech':
        keyword = ["联合研发", "技术外包", "知识产权"][i % 3];
        topic = ["新技术攻关", "UI 设计", "专利申请"][i % 3];
        break;
      case 'finance':
        keyword = ["企业贷款", "融资服务", "财务咨询"][i % 3];
        topic = ["信用贷", "天使投资", "税务筹划"][i % 3];
        break;
      case 'beijing-suzhou':
        keyword = ["京苏合作", "异地参展", "文化融合"][i % 3];
        topic = ["园区共建", "北京展会", "苏州园林游"][i % 3];
        break;
      case 'events':
        keyword = ["商业活动", "培训活动", "团建联谊"][i % 3];
        topic = ["新品发布", "管理沙龙", "年会晚会"][i % 3];
        break;
      default:
        keyword = ["技术创新", "业务拓展", "资源合作"][i % 3];
        topic = ["战略合作", "市场开发", "资源整合"][i % 3];
    }
    
    const title = `${company.name} · ${keyword}-${topic}`;
    const content = generatePostContent(company, channel, keyword, topic);
    
    posts.push({
      id: `post-${i}`,
      title,
      author: company,
      content,
      timestamp: new Date(Date.now() - Math.random() * 7 * 24 * 60 * 60 * 1000).toLocaleString("zh-CN"),
      likes: Math.floor(Math.random() * 200),
      commentsCount: Math.floor(Math.random() * 50) + 1,
      views: Math.floor(Math.random() * 1000) + 500,
      channel
    });
  }
  
  return posts;
}

